import{_ as e,o as i,c as r,a7 as a}from"./chunks/framework.C5fSpjcB.js";const f=JSON.parse('{"title":"Silver Core Communication","description":"","frontmatter":{},"headers":[],"relativePath":"en/story/silver-core.md","filePath":"en/story/silver-core.md","lastUpdated":1775394001000}'),o={name:"en/story/silver-core.md"};function n(s,t,l,d,c,h){return i(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="silver-core-communication" tabindex="-1">Silver Core Communication <a class="header-anchor" href="#silver-core-communication" aria-label="Permalink to &quot;Silver Core Communication&quot;">​</a></h1><p><strong>Silver Core Communication</strong> is Morimens&#39; affinity system. It allows the Keeper to build relationships with Awakeners through interactions, gifts, and shared experiences, unlocking story content and gameplay bonuses.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td>System Type</td><td>Affinity / Bond system</td></tr><tr><td>Purpose</td><td>Unlock character stories, voice lines, stat bonuses</td></tr><tr><td>Progression</td><td>Raise affinity levels through various activities</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>The Silver Core Communication system is accessed from the main menu. Through this interface, the Keeper can interact with any Awakener they have obtained. The system ties directly into the game&#39;s lore -- the &quot;Silver Core&quot; is a communication device that allows the Keeper to connect with the minds and memories of Awakened Ones, reflecting the game&#39;s central themes of memory and human connection.</p><ol><li><strong>Interact</strong> with Awakeners through the Silver Core Communication interface. Daily interactions are available and accumulate affinity over time.</li><li><strong>Give gifts</strong> -- Each Awakener has preferred and disliked gifts based on their personality and lore background. Preferred gifts grant significantly more affinity than neutral ones.</li><li><strong>Include in battles</strong> -- Using an Awakener in your combat party slowly builds affinity through shared experience.</li><li><strong>Complete character quests</strong> -- Special quests tied to each Awakener&#39;s backstory that grant substantial affinity boosts upon completion.</li></ol><h2 id="affinity-levels" tabindex="-1">Affinity Levels <a class="header-anchor" href="#affinity-levels" aria-label="Permalink to &quot;Affinity Levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>Unlocks</th></tr></thead><tbody><tr><td>1</td><td>Basic interaction dialogue</td></tr><tr><td>2</td><td>First personal story episode</td></tr><tr><td>3</td><td>New voice lines</td></tr><tr><td>4</td><td>Stat bonus (minor)</td></tr><tr><td>5</td><td>Second personal story episode</td></tr><tr><td>6</td><td>Additional voice lines</td></tr><tr><td>7</td><td>Stat bonus (moderate)</td></tr><tr><td>8</td><td>Third personal story episode</td></tr><tr><td>9</td><td>Special cosmetic content (expressions, profile items)</td></tr><tr><td>10</td><td>Final personal story episode and full stat bonus</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Exact affinity point thresholds for each level vary and may be adjusted with game updates. Higher levels require significantly more affinity points than lower ones.</p></div><p>Each affinity level unlocks new content:</p><ul><li><strong>Story Episodes</strong> -- Personal backstory chapters for the Awakener.</li><li><strong>Voice Lines</strong> -- New dialogue and voice clips.</li><li><strong>Stat Bonuses</strong> -- Minor stat increases for the Awakener.</li><li><strong>Special Content</strong> -- Expressions, profile items, or other cosmetics.</li></ul><h2 id="gift-giving" tabindex="-1">Gift Giving <a class="header-anchor" href="#gift-giving" aria-label="Permalink to &quot;Gift Giving&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gift Preference</th><th>Affinity Gain</th></tr></thead><tbody><tr><td>Preferred</td><td>High</td></tr><tr><td>Neutral</td><td>Low</td></tr><tr><td>Disliked</td><td>Negative or none</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Pay attention to each Awakener&#39;s personality and lore to guess their gift preferences. Preferred gifts grant significantly more affinity than neutral ones.</p></div><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li><strong>Interact daily</strong> -- Small daily interactions add up over time.</li><li><strong>Focus on your main team</strong> -- Prioritize affinity for Awakeners you use in combat to gain their stat bonuses.</li><li><strong>Read the stories</strong> -- Character stories unlocked through Silver Core Communication provide valuable lore context.</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./character-stories.html">Character Stories</a></li><li><a href="./">Story &amp; Lore Overview</a></li><li><a href="./../awakeners/">Awakener Overview</a></li></ul>',19)])])}const m=e(o,[["render",n]]);export{f as __pageData,m as default};
